parameters.jsCode:
const input = $input.first().json;

function cleanText(text) {
  if (!text) return "";

  return text
    // Remove asterisks
    .replace(/\*/g, "")
    // Remove standalone dashes (bullets/separators, not hyphens in words)
    .replace(/(?<!\w)-(?!\w)/g, "")
    // Remove excessive blank lines
    .replace(/\n{3,}/g, "\n\n")
    // Trim whitespace per line
    .split("\n").map(line => line.trim()).join("\n")
    // Fix missing space after punctuation
    .replace(/([.!?])([A-Z])/g, "$1 $2")
    // Fix double spaces
    .replace(/ {2,}/g, " ")
    // Capitalize first letter
    .replace(/^[a-z]/, c => c.toUpperCase())
    // Trim overall
    .trim();
}

return [{
  json: {
    ...input,
    postCopy: cleanText(input.postCopy),
    approvedAngle: cleanText(input.approvedAngle),
  }
}];

