const input = $input.first().json;
let text = input.postCopy || input.output || ""

// ── 1. Extract IMAGE PROMPT section ──────────────────────────────
const imageSplit = text.match(/IMAGE PROMPT\s*\n([\s\S]+?)$/i);
const imagePrompt = imageSplit ? imageSplit[1].trim() : "";

// ── 2. Remove IMAGE PROMPT block from postCopy ───────────────────
let cleanedCopy = text.replace(/IMAGE PROMPT\s*\n[\s\S]+$/i, "").trim();

// ── 3. Clean the copy (your existing cleaning logic) ─────────────
function cleanText(t) {
  if (!t) return "";
  return t
    .replace(/\*/g, "")                          // remove asterisks
    .replace(/(?<!\w)-(?!\w)/g, "")              // remove standalone dashes
    .replace(/\n{3,}/g, "\n\n")                  // collapse excess blank lines
    .split("\n").map(l => l.trim()).join("\n")    // trim each line
    .replace(/([.!?])([A-Z])/g, "$1 $2")         // space after punctuation
    .replace(/ {2,}/g, " ")                      // remove double spaces
    .replace(/^[a-z]/, c => c.toUpperCase())     // capitalize first letter
    .trim();
}

cleanedCopy = cleanText(cleanedCopy);

return [{
  json: {
    ...input,
    postCopy: cleanedCopy,      // clean copy only, no image prompt block
    imagePrompt: imagePrompt,   // extracted, ready for DALL-E node
  }
}];
